import torch
from torchvision import models, transforms
from torch.utils.data import DataLoader, Dataset
from PIL import Image

# Define a simple dataset class
class CustomDataset(Dataset):
    def __init__(self, image_paths, labels, transform=None):
        self.image_paths = image_paths
        self.labels = labels
        self.transform = transform

    def __len__(self):
        return len(self.image_paths)

    def __getitem__(self, idx):
        image = Image.open(self.image_paths[idx])
        if self.transform:
            image = self.transform(image)
        label = torch.tensor(self.labels[idx], dtype=torch.long)
        return image, label

# Load a pretrained model
model_url = 'https://example.com/pretrained_model.pth'
model = models.resnet18(pretrained=True)

# Freeze all layers for transfer learning
for param in model.parameters():
    param.requires_grad = False

# Modify the last layer to match the number of classes in your dataset
num_classes = 10
model.fc = torch.nn.Linear(model.fc.in_features, num_classes)

# Define transformations
transform = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

# Load model checkpoint
checkpoint = torch.load(model_url)
model.load_state_dict(checkpoint['model_state_dict'])

# Define a custom dataset and dataloader
image_paths = ['path/to/image1.jpg', 'path/to/image2.jpg']
labels = [0, 1]
dataset = CustomDataset(image_paths, labels, transform=transform)
dataloader = DataLoader(dataset, batch_size=4, shuffle=True)

# Define loss function and optimizer
criterion = torch.nn.CrossEntropyLoss()
optimizer = torch.optim.SGD(model.fc.parameters(), lr=0.001, momentum=0.9)

# Fine-tune the model
num_epochs = 5
for epoch in range(num_epochs):
    for images, labels in dataloader:
        optimizer.zero_grad()
        outputs = model(images)
        loss = criterion(outputs, labels)
        loss.backward()
        optimizer.step()

    print(f'Epoch [{epoch+1}/{num_epochs}], Loss: {loss.item():.4f}')

# Save the fine-tuned model
torch.save({
    'model_state_dict': model.state_dict(),
}, 'fine_tuned_model.pth')